import org.apache.storm.Config;
import org.apache.storm.LocalCluster;
import org.apache.storm.StormSubmitter;
import org.apache.storm.topology.TopologyBuilder;
import org.apache.storm.topology.base.BaseRichSpout;
import org.apache.storm.topology.base.BaseRichBolt;
import org.apache.storm.tuple.Fields;
import org.apache.storm.tuple.Values;
import org.apache.storm.task.OutputCollector;
import org.apache.storm.task.TopologyContext;
import org.apache.storm.spout.SpoutOutputCollector;
import org.apache.storm.tuple.Tuple;
import java.util.*;
import java.util.concurrent.atomic.AtomicLong;

// === SPOUT: Source of log data ===
class LogSpout extends BaseRichSpout {
    private SpoutOutputCollector collector;
    private Random random;
    private final String[] logLevels = {"INFO", "DEBUG", "WARN", "ERROR", "FATAL"};
    private final String[] services = {"auth-service", "payment-service", "api-gateway", "user-service"};
    private AtomicLong msgId;

    public void open(Map config, TopologyContext context, SpoutOutputCollector collector) {
        this.collector = collector;
        this.random = new Random();
        this.msgId = new AtomicLong(0);
    }

    public void nextTuple() {
        // Generate random log entry
        String service = services[random.nextInt(services.length)];
        String level = logLevels[random.nextInt(logLevels.length)];
        long timestamp = System.currentTimeMillis();
        String message = "Log message from " + service;

        // Emit tuple with message ID for tracking (guaranteed processing)
        long currentMsgId = msgId.incrementAndGet();
        collector.emit(new Values(service, level, timestamp, message), currentMsgId);

        // Small delay to simulate real-time streaming
        try { Thread.sleep(100); } catch (InterruptedException e) {}
    }

    public void declareOutputFields(org.apache.storm.topology.OutputFieldsDeclarer declarer) {
        // Declare output fields
        declarer.declare(new Fields("service", "level", "timestamp", "message"));
    }
}

// === BOLT 1: Parse and filter logs ===
class LogFilterBolt extends BaseRichBolt {
    private OutputCollector collector;

    public void prepare(Map config, TopologyContext context, OutputCollector collector) {
        this.collector = collector;
    }

    public void execute(Tuple tuple) {
        String service = tuple.getStringByField("service");
        String level = tuple.getStringByField("level");
        long timestamp = tuple.getLongByField("timestamp");
        String message = tuple.getStringByField("message");

        // Filter: only process ERROR and FATAL
        if ("ERROR".equals(level) || "FATAL".equals(level)) {
            // Emit to critical stream
            collector.emit("critical-stream", new Values(service, level, timestamp, message));
        } else {
            // Emit to normal stream
            collector.emit("normal-stream", new Values(service, level, timestamp, message));
        }

        // Acknowledge the tuple (guaranteed processing)
        collector.ack(tuple);
    }

    public void declareOutputFields(org.apache.storm.topology.OutputFieldsDeclarer declarer) {
        // Declare multiple streams
        declarer.declareStream("critical-stream", new Fields("service", "level", "timestamp", "message"));
        declarer.declareStream("normal-stream", new Fields("service", "level", "timestamp", "message"));
    }
}

// === BOLT 2: Aggregate error counts by service (Fields Grouping) ===
class ErrorCounterBolt extends BaseRichBolt {
    private OutputCollector collector;
    private Map<String, AtomicLong> errorCounts;

    public void prepare(Map config, TopologyContext context, OutputCollector collector) {
        this.collector = collector;
        this.errorCounts = new HashMap<>();
    }

    public void execute(Tuple tuple) {
        String service = tuple.getStringByField("service");
        String level = tuple.getStringByField("level");

        // Update count for this service
        errorCounts.putIfAbsent(service, new AtomicLong(0));
        long count = errorCounts.get(service).incrementAndGet();

        // Emit aggregated count
        collector.emit(new Values(service, count));

        collector.ack(tuple);
    }

    public void declareOutputFields(org.apache.storm.topology.OutputFieldsDeclarer declarer) {
        declarer.declare(new Fields("service", "error_count"));
    }
}

// === BOLT 3: Output bolt (Global Grouping - single task) ===
class LoggingBolt extends BaseRichBolt {
    private OutputCollector collector;

    public void prepare(Map config, TopologyContext context, OutputCollector collector) {
        this.collector = collector;
    }

    public void execute(Tuple tuple) {
        // Print to console (in production, would write to file/DB)
        System.out.println("[LOG-BOLT] Service: " + tuple.getStringByField("service") + 
                          ", Errors: " + tuple.getLongByField("error_count"));

        collector.ack(tuple);
    }

    public void declareOutputFields(org.apache.storm.topology.OutputFieldsDeclarer declarer) {
        // No output streams
    }
}

// === MAIN TOPOLOGY BUILDER ===
public class StormLogProcessingTopology {
    public static void main(String[] args) throws Exception {
        // Create Topology Builder
        TopologyBuilder builder = new TopologyBuilder();

        // Set Spout (parallelism = 2 executors)
        builder.setSpout("log-spout", new LogSpout(), 2);

        // Set Filter Bolt (parallelism = 4, Shuffle Grouping)
        builder.setBolt("filter-bolt", new LogFilterBolt(), 4)
            .shuffleGrouping("log-spout");

        // Set Error Counter Bolt (parallelism = 3, Fields Grouping by service)
        // This ensures all logs for same service go to same task
        builder.setBolt("counter-bolt", new ErrorCounterBolt(), 3)
            .fieldsGrouping("filter-bolt", "critical-stream", new Fields("service"));

        // Set Logging Bolt (parallelism = 1, Global Grouping)
        // All aggregated results go to single task for final output
        builder.setBolt("logging-bolt", new LoggingBolt(), 1)
            .globalGrouping("counter-bolt");

        // Configure topology
        Config config = new Config();
        config.setDebug(true);
        config.setNumWorkers(2);  // Number of worker processes

        // Submit topology
        if (args != null && args.length > 0) {
            // Run on remote cluster
            String topologyName = args[0];
            StormSubmitter.submitTopology(topologyName, config, builder.createTopology());
        } else {
            // Run locally for testing
            LocalCluster cluster = new LocalCluster();
            cluster.submitTopology("log-processing-topology", config, builder.createTopology());

            // Run for 30 seconds then kill
            Thread.sleep(30000);
            cluster.killTopology("log-processing-topology");
            cluster.shutdown();
        }
    }
}
